tests.test_body:
target datalayout = "e-p:64:64:64-i1:8:8-i8:8:8-i16:16:16-i32:32:32-i64:64:64-f32:32:32-f64:64:64-v64:64:64-v128:128:128-a0:0:64-s0:64:64-f80:128:128-n8:16:32:64"

@g_bool = external global i8, align 1
@g_long = external global i64, align 8

define void @test_combine_metadata(i1 %c, i64 %arg) {
entry:
  %val = alloca i8, align 1
  br label %loop

loop:                                             ; preds = %if.then, %entry
  %phi = phi ptr [ @g_long, %if.then ], [ %val, %entry ]
  store i64 %arg, ptr @g_long, align 8, !tbaa !0
  %trunc = trunc i64 %arg to i8
  store i8 %trunc, ptr %val, align 1, !tbaa !4
  br i1 %c, label %if.then, label %if.else

if.else:                                          ; preds = %loop
  %v2 = load i8, ptr %phi, align 1, !tbaa !6
  store i8 %v2, ptr @g_bool, align 8, !tbaa !0
  br label %if.then

if.then:                                          ; preds = %if.else, %loop
  %v1 = load i8, ptr %phi, align 1, !tbaa !4
  store i8 %v1, ptr @g_bool, align 1
  br label %loop
}

!0 = !{!1, !1, i64 0}
!1 = !{!"long", !2, i64 0}
!2 = !{!"omnipotent char", !3, i64 0}
!3 = !{!"Simple C/C++ TBAA"}
!4 = !{!5, !5, i64 0}
!5 = !{!"_Bool", !2, i64 0}
!6 = !{!2, !2, i64 0}
